import{_ as t,o as n,c as a,a2 as i}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"TongAgents","description":"","frontmatter":{"title":"TongAgents","status":"research-limited"},"headers":[],"relativePath":"research/agents/tongagents/index.md","filePath":"research/agents/tongagents/index.md"}'),r={name:"research/agents/tongagents/index.md"};function o(s,e,d,l,h,c){return n(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="tongagents" tabindex="-1">TongAgents <a class="header-anchor" href="#tongagents" aria-label="Permalink to &quot;TongAgents&quot;">​</a></h1><blockquote><p>A coding agent built by BIGAI (Beijing Institute for General Artificial Intelligence) that achieved top-3 performance on Terminal-Bench 2.0, though with very limited public documentation.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>TongAgents is a coding agent system developed by <strong>BIGAI</strong> (北京通用人工智能研究院, Beijing Institute for General Artificial Intelligence), a leading Chinese AI research institute focused on artificial general intelligence. The agent appeared on the Terminal-Bench 2.0 leaderboard in March 2026 and quickly demonstrated strong performance across multiple foundation models.</p><p><strong>⚠️ Research Limitation:</strong> As of this writing, no public GitHub repository, academic paper, or detailed technical documentation has been found for TongAgents. This analysis is based on benchmark results, BIGAI&#39;s broader research portfolio, and reasonable inferences from the agent&#39;s naming conventions and performance patterns. Claims are clearly marked as known facts vs. informed speculation.</p><h2 id="what-we-know-confirmed" tabindex="-1">What We Know (Confirmed) <a class="header-anchor" href="#what-we-know-confirmed" aria-label="Permalink to &quot;What We Know (Confirmed)&quot;">​</a></h2><ul><li><strong>Terminal-Bench 2.0 Rank #3</strong> with Gemini 3.1 Pro: <strong>80.2% ±2.6</strong> (submitted 2026-03-13)</li><li><strong>Terminal-Bench 2.0 Rank #13</strong> with Claude Opus 4.6: <strong>~71.9%</strong> (estimated from leaderboard position)</li><li>Built by BIGAI, the same institute behind TongSIM, tong-geometry, and other &quot;Tong&quot;-prefixed projects</li><li>The name follows BIGAI&#39;s established naming convention where &quot;Tong&quot; (通, meaning &quot;general/universal&quot;) is a prefix for their tools and platforms</li></ul><h2 id="bigai-the-organization" tabindex="-1">BIGAI (The Organization) <a class="header-anchor" href="#bigai-the-organization" aria-label="Permalink to &quot;BIGAI (The Organization)&quot;">​</a></h2><p>BIGAI is a prominent Chinese AI research institute founded by <strong>Professor Zhu Songchun (朱松纯)</strong>, a well-known computer vision and AI researcher with a background at UCLA. The institute focuses on:</p><ul><li><strong>AGI research</strong> — cognitive architectures, reasoning, planning</li><li><strong>Embodied intelligence</strong> — robotics, humanoid control (LIFT, ECO)</li><li><strong>Simulation platforms</strong> — TongSIM (physics simulation, open-sourced, trending on HuggingFace)</li><li><strong>Game AI</strong> — CivRealm (strategy game environment)</li><li><strong>Computer vision</strong> — extensive publication history at CVPR, ICLR, CoRL</li></ul><p>BIGAI has published in top venues including Nature Machine Intelligence and Science. Their GitHub organization (<code>bigai-ai</code>) has 34+ public repositories, predominantly in robotics and embodied AI. The move into coding agents represents an expansion of their agent research portfolio.</p><h2 id="key-results" tabindex="-1">Key Results <a class="header-anchor" href="#key-results" aria-label="Permalink to &quot;Key Results&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>Model</th><th>Score</th><th>Rank</th><th>Date</th></tr></thead><tbody><tr><td>Terminal-Bench 2.0</td><td>Gemini 3.1 Pro</td><td>80.2% ±2.6</td><td>#3</td><td>2026-03-13</td></tr><tr><td>Terminal-Bench 2.0</td><td>Claude Opus 4.6</td><td>~71.9%</td><td>#13</td><td>2026-03</td></tr></tbody></table><p>The ~8 percentage point gap between models is notable and discussed further in <a href="./context-management.html">context-management.md</a>.</p><h2 id="what-makes-it-interesting" tabindex="-1">What Makes It Interesting <a class="header-anchor" href="#what-makes-it-interesting" aria-label="Permalink to &quot;What Makes It Interesting&quot;">​</a></h2><ol><li><strong>Institutional backing</strong> — BIGAI is a well-funded AGI-focused research institute, not a startup or solo project</li><li><strong>Multi-model support</strong> — tested with both Gemini and Claude, suggesting model-agnostic design</li><li><strong>Rapid entry</strong> — appeared on leaderboards without prior public announcements or papers</li><li><strong>&quot;Tong&quot; ecosystem</strong> — part of a broader family of BIGAI tools and platforms</li><li><strong>Chinese AI research context</strong> — represents growing Chinese institutional investment in coding agents</li></ol><h2 id="file-index" tabindex="-1">File Index <a class="header-anchor" href="#file-index" aria-label="Permalink to &quot;File Index&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Contents</th></tr></thead><tbody><tr><td><a href="./architecture.html">architecture.md</a></td><td>Inferred architecture based on naming and performance patterns</td></tr><tr><td><a href="./agentic-loop.html">agentic-loop.md</a></td><td>What can be inferred about the execution loop</td></tr><tr><td><a href="./tool-system.html">tool-system.md</a></td><td>Likely tool capabilities based on Terminal-Bench requirements</td></tr><tr><td><a href="./context-management.html">context-management.md</a></td><td>Inferences from model performance gaps</td></tr><tr><td><a href="./unique-patterns.html">unique-patterns.md</a></td><td>Distinctive aspects and institutional context</td></tr><tr><td><a href="./benchmarks.html">benchmarks.md</a></td><td>Detailed Terminal-Bench 2.0 results and comparisons</td></tr><tr><td><a href="./references.html">references.md</a></td><td>Links to BIGAI, Terminal-Bench, and related projects</td></tr></tbody></table>',18)])])}const u=t(r,[["render",o]]);export{m as __pageData,u as default};
